// Liquid Prism — colorful osc blend with self-feedback
speed = 0.5

AUDIO.bins = 6; AUDIO.smooth = 0.82; AUDIO.gain = 30; AUDIO.apply();
var _lo = function(){ return a.fft[0] || 0 };
var _mi = function(){ return a.fft[2] || 0 };
var _hi = function(){ return a.fft[4] || 0 };
var low  = env(_lo, 0.35, 0.04);
var mid  = env(_mi, 0.3, 0.05);
var high = env(_hi, 0.25, 0.06);
var amp  = function(){ return (low() + mid() + high()) * 0.6 };

osc(15, 0.06, 1.8)
  .color(
    () => 0.9 + low() * 0.5,
    () => 0.3 + mid() * 0.4,
    () => 0.6 + high() * 0.4
  )
  .blend(osc(6, 0.1, 0.8).rotate(() => time * 0.04), 0.4)
  .modulate(noise(2.5, 0.3), () => 0.1 + low() * 0.008)
  .blend(src(o0).rotate(() => Math.sin(time * 0.03) * 0.003).hue(() => amp() * 0.006), 0.84)
  .saturate(() => 1.2 + low() * 0.3)
  .colorama(() => 0.001 + amp() * 0.003)
  .hue(() => mid() * 0.015)
  .contrast(() => 1.02 + low() * 0.08)
  .brightness(0.02)
  .out(o0)
